// Get the input data
const items = $input.all();

// Initialize variable
let targetId = null;

// Loop through the input (typically just 1 item)
for (const item of items) {

  // 1. Access the 'fields' array specifically from your JSON structure
  const allFields = item.json.fields || [];

  // 2. Find the field where fieldKey matches 'contact.assistantchat_last_message'
  const matchedField = allFields.find(field => field.fieldKey === 'contact.assistantchat_last_message');

  // 3. If found, save the ID
  if (matchedField) {
    targetId = matchedField.id;
    break; // Stop looking once found
  }
}

// Return the result
return {
  json: {
    name: 'assistantchat_last_message',
    id: targetId || "NOT_FOUND" 
  }
};

